set-variable.value:
#[%dw 2.0
output application/java

---
"<!DOCTYPE html>
<html>
<head>
<meta charset='UTF-8'>
<title>Real Bank - Account Not Found</title>

<style>
*{
margin:0;
padding:0;
box-sizing:border-box;
font-family:'Segoe UI',Arial,sans-serif;
}

body{
background:#eef3f8;
padding:30px;
color:#333;
}

.wrapper{
max-width:760px;
margin:auto;
background:#ffffff;
border-radius:18px;
overflow:hidden;
box-shadow:0 15px 35px rgba(0,0,0,.15);
}

.header{
background:linear-gradient(135deg,#8B0000,#C62828,#E53935);
padding:40px;
text-align:center;
color:white;
}

.logo{
font-size:36px;
font-weight:bold;
}

.tagline{
margin-top:8px;
font-size:15px;
opacity:.9;
}

.hero{
padding:35px;
text-align:center;
background:#FFF5F5;
}

.hero h2{
color:#C62828;
margin-bottom:15px;
font-size:30px;
}

.hero p{
font-size:15px;
line-height:28px;
color:#555;
}

.alert{
margin:25px;
padding:20px;
background:#FDECEC;
border-left:6px solid #D32F2F;
border-radius:10px;
font-size:17px;
font-weight:bold;
color:#B71C1C;
text-align:center;
}

.card{
margin:30px;
border:1px solid #E5E5E5;
border-radius:15px;
overflow:hidden;
}

.card-title{
background:#C62828;
color:white;
padding:18px;
font-size:20px;
font-weight:bold;
}

table{
width:100%;
border-collapse:collapse;
}

td{
padding:18px;
border-bottom:1px solid #EEEEEE;
}

td:first-child{
width:38%;
background:#FAFAFA;
font-weight:bold;
color:#555;
}

.failed{
background:#FDECEC;
color:#C62828;
padding:6px 18px;
border-radius:20px;
font-weight:bold;
}

.info{
margin:0 30px 30px;
background:#FFF8E8;
border-left:6px solid orange;
padding:22px;
border-radius:10px;
}

.info h3{
margin-bottom:12px;
color:#C97B00;
}

.info li{
margin:10px 0;
}

.footer{
background:#002B5B;
padding:35px;
text-align:center;
color:white;
}

.footer p{
line-height:24px;
font-size:13px;
}

.support{
margin-top:20px;
padding-top:20px;
border-top:1px solid rgba(255,255,255,.2);
}
</style>

</head>

<body>

<div class='wrapper'>

<div class='header'>

<div class='logo'>
🏦 REAL BANK
</div>

<div class='tagline'>
Safe • Secure • Trusted Banking
</div>

</div>

<div class='hero'>

<h2>
❌ Account Not Found
</h2>

<p>

We could not find any account associated with the customer details you provided.

Please verify your information and try again.

</p>

</div>

<div class='alert'>

⚠ An account does not exist with the provided customer details.

</div>

<div class='card'>

<div class='card-title'>
📄 Request Status
</div>

<table>

<tr>
<td>Status</td>
<td><span class='failed'>FAILED</span></td>
</tr>

<tr>
<td>Status Code</td>
<td>404</td>
</tr>

<tr>
<td>Message</td>
<td>
An account does not exist with the provided customer details.
Please verify your information and try again.
</td>
</tr>

</table>

</div>

<div class='info'>

<h3>💡 What You Can Do</h3>

<ul>

<li>Verify your Account Number or Customer Details.</li>

<li>Ensure you entered the correct Aadhaar Number and Email Address.</li>

<li>If you are a new customer, please complete the account registration process first.</li>

<li>If you believe this message is incorrect, contact Real Bank Customer Support.</li>

</ul>

</div>

<div class='footer'>

<h3>

Thank You For Banking With Us ❤️

</h3>

<p>

Customer Care : +91 9494207062

<br>

Email : narsingbeesetti22@gmail.com

<br><br>

© 2026 Real Bank

<br>

Safe Banking | Digital Banking | Secure Transactions

</p>

<div class='support'>

This is an automated email. Please do not reply.

</div>

</div>

</div>

</body>

</html>"]
